/* HADO app 3.0.0.0 Update07.6: role-aware suitability score gate */
(()=>{'use strict';
const LABELS={main_general:'主将',vice_general:'副将',support_general:'補佐',advisor_general:'参軍',attendant:'侍従'};
const SENSITIVE=new Set(Object.keys(LABELS));
const RULES=[
 ['main_general',/(?:^|[■▼●。；;\n　\s])主将(?:の)?(?:際|時|限定|として|に編制)/],
 ['vice_general',/(?:^|[■▼●。；;\n　\s])副将(?:の)?(?:際|時|限定|として|に編制)/],
 ['support_general',/(?:^|[■▼●。；;\n　\s])補佐(?:の)?(?:際|時|限定|として|に編制)/],
 ['advisor_general',/(?:^|[■▼●。；;\n　\s])参軍(?:の)?(?:際|時|限定|として|に編制|起用)/],
 ['attendant',/(?:^|[■▼●。；;\n　\s])侍従(?:の)?(?:際|時|限定|として|に編制)/]
];
const flat=v=>Array.isArray(v)?v.map(flat).join(' '):(v&&typeof v==='object'?Object.values(v).map(flat).join(' '):String(v??''));
const norm=v=>String(v??'').normalize('NFKC').replace(/\s+/g,'').toLowerCase();
const rowText=row=>flat([row?.label,row?.statusEffectName,row?.featureId,row?.matchedText,row?.source,row?.sourceType,row?.kind,row?.category]);
function gate(row,roleId){
 const role=String(roleId||'').trim(),text=rowText(row);
 if(!SENSITIVE.has(role))return {allowed:true,reason:'role-insensitive',requiredRoleIds:[]};
 if(role==='advisor_general'&&!/参軍|advisor/.test(norm(text)))return {allowed:false,reason:'advisor-source-only',requiredRoleIds:['advisor_general']};
 const required=RULES.filter(([,rx])=>rx.test(text)).map(([id])=>id);
 if(!required.length)return {allowed:true,reason:'no-explicit-role-gate',requiredRoleIds:[]};
 return required.includes(role)?{allowed:true,reason:'explicit-role-gate-matched',requiredRoleIds:required}:{allowed:false,reason:`role-mismatch:${required.join('|')}`,requiredRoleIds:required};
}
function install(){
 const api=window.HadoTypeScore;if(!api||api.__roleGateInstalled)return false;
 const original=api.score;
 api.score=function(entity,rule,context={}){
  const roleId=String(context?.roleId||entity?.roleId||'').trim(),excluded=[];
  const clone={...entity};
  ['typeFeatures','statusEffectRefs'].forEach(key=>{clone[key]=(Array.isArray(entity?.[key])?entity[key]:[]).filter(row=>{const result=gate(row,roleId);if(!result.allowed)excluded.push({key,reason:result.reason,requiredRoleIds:result.requiredRoleIds,matchedText:String(row?.matchedText||rowText(row)).slice(0,180)});return result.allowed})});
  const result=original(clone,rule);
  const reasons={};excluded.forEach(row=>reasons[row.reason]=(reasons[row.reason]||0)+1);
  result.roleId=roleId;result.roleAudit={roleId,roleLabel:LABELS[roleId]||roleId,excludedRowCount:excluded.length,exclusionReasons:reasons,excluded:excluded.slice(0,20)};
  return result;
 };
 api.roleGate=gate;api.ROLE_LABELS=LABELS;api.__roleGateInstalled=true;return true;
}
if(!install())addEventListener('DOMContentLoaded',install,{once:true});
})();

