function score(x,roleId){if(!window.HadoTypeScore)throw Error('適合スコア共通処理が読み込まれていません。');return window.HadoTypeScore.score(x,type(),{roleId})}
function isAdvisorCandidate(v){try{const item=typeof findItemByDisplayName==='function'?findItemByDisplayName('generals',canonicalName(v)||displayName(v)):null;if(item&&typeof getAdvisorSkillEntriesForGeneralItem==='function')return getAdvisorSkillEntriesForGeneralItem(item).length>0}catch{}return /参軍|advisor/.test(norm(flat(v)))}
function sourceRows(role){const direct=st.data.roles.filter(v=>v.roleId===role);if(role!=='advisor_general'||direct.length)return direct;return st.data.roles.filter(v=>v.roleId==='main_general').filter(isAdvisorCandidate).map(v=>({...v,roleId:'advisor_general',roleDerivedFrom:'main_general'}))}
function roleRows(role){const q=norm(st.q),source=sourceRows(role),scored=source.map(v=>({...v,_s:score(v,role)})),matched=scored.filter(v=>v._s.matchedCount>0),rows=matched.filter(v=>!q||norm(flat([v.displayName,v.name,v.typeFeatures,v.statusEffectRefs])).includes(q)).sort((a,b)=>b._s.confirmedScore-a._s.confirmedScore||b._s.conditionalMaxScore-a._s.conditionalMaxScore||Number(a.sourceIndex||0)-Number(b.sourceIndex||0)),reasons={};let excludedRoleRows=0;scored.forEach(v=>{excludedRoleRows+=Number(v._s.roleAudit?.excludedRowCount||0);Object.entries(v._s.roleAudit?.exclusionReasons||{}).forEach(([k,n])=>reasons[k]=(reasons[k]||0)+Number(n||0))});try{if(typeof state==='object'){state.diagnostics=state.diagnostics||{};state.diagnostics.typeCandidateRoles=state.diagnostics.typeCandidateRoles||{};state.diagnostics.typeCandidateRoles[role]={timestamp:new Date().toISOString(),typeId:st.sel?.typeId||'',roleId:role,sourceCount:source.length,scoreMatchedCount:matched.length,displayedCount:rows.length,excludedRoleRows,exclusionReasons:reasons}}}catch{}return rows}
function rows(){return roleRows(st.role)}
